"use client";
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter, useParams } from 'next/navigation';
import { 
  ExternalLink, GitBranch, Clock, User, ArrowLeft, 
  BrainCircuit, ShieldAlert, CheckCircle2, ChevronRight, Terminal 
} from 'lucide-react';
import RiskBadge from '@/components/ui/RiskBadge';
import HindsightPanel from '@/components/ui/HindsightPanel';
import { getStoredData, Deployment } from '@/lib/mockData';

export default function DeploymentDetailPage() {
  const router = useRouter();
  const params = useParams();
  const id = params?.id as string;
  
  const [deployment, setDeployment] = useState<Deployment | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (id) {
      const data = getStoredData();
      const match = data.deployments.find((d: Deployment) => d.id === id);
      setDeployment(match || data.deployments[0]); // fallback to first
      setLoading(false);
    }
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-[70vh] flex items-center justify-center text-xs text-[#8B91B5] italic">
        Loading deployment details...
      </div>
    );
  }

  if (!deployment) {
    return (
      <div className="p-8 text-center text-xs text-[#EF4444]">
        Deployment record not found.
      </div>
    );
  }

  // Risk Score color definitions
  const isProd = deployment.status.toLowerCase() === 'production';
  const envBadgeColor = isProd 
    ? 'text-[#22C55E] bg-[#22C55E]/10 border-[#22C55E]/20' 
    : 'text-[#4F7FFF] bg-[#4F7FFF]/10 border-[#4F7FFF]/20';

  // SVG Gauge details
  const radius = 52;
  const stroke = 8;
  const normalizedRadius = radius - stroke * 2;
  const circumference = normalizedRadius * 2 * Math.PI;
  const strokeDashoffset = circumference - (deployment.risk / 100) * circumference;

  let gaugeColor = 'stroke-[#22C55E]';
  let gaugeText = 'text-[#22C55E]';
  if (deployment.risk > 80) {
    gaugeColor = 'stroke-[#EF4444]';
    gaugeText = 'text-[#EF4444]';
  } else if (deployment.risk > 60) {
    gaugeColor = 'stroke-[#F97316]';
    gaugeText = 'text-[#F97316]';
  } else if (deployment.risk > 30) {
    gaugeColor = 'stroke-[#EAB308]';
    gaugeText = 'text-[#EAB308]';
  }

  // Mocked risk factors & recommendations matching score
  const riskFactors = deployment.risk > 80 ? [
    "Critical API interface alterations detected",
    "High incident correlation with Friday deployments",
    "Database column modifications require exclusive table locks"
  ] : deployment.risk > 50 ? [
    "Database schema index alterations detected",
    "Average deployment failure rate of service is elevated",
    "Dependencies updated across core libraries"
  ] : [
    "Standard non-breaking patch release",
    "Full testing pipeline passed with zero warnings"
  ];

  const recommendations = deployment.risk > 80 ? [
    "Execute isolated integrations checks on auth pathways first",
    "Reschedule deployment window to early weekdays to ensure full SRE response coverage",
    "Deploy as standard blue-green cluster with 10% canary traffic weights"
  ] : deployment.risk > 50 ? [
    "Run smoke testing suite on pre-prod environments",
    "Validate rollback script databases backups prior to promotion"
  ] : [
    "Proceed with standard production release pipelines"
  ];

  return (
    <div className="p-8 space-y-6 animate-fade-in max-w-7xl mx-auto">
      
      {/* Back Button */}
      <button 
        onClick={() => router.back()}
        className="inline-flex items-center gap-2 text-xs text-[#8B91B5] hover:text-[#F0F2FF] transition-colors font-medium border border-[#2A2F45] bg-[#13161E] px-3.5 py-1.5 rounded-lg"
      >
        <ArrowLeft size={14} /> Back to dashboard
      </button>

      {/* Grid: Header details & circular risk gauge */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        
        {/* Left main details */}
        <div className="lg:col-span-8 space-y-6">
          
          {/* Metadata Card */}
          <div className="card-bg rounded-xl p-6 space-y-6">
            <div className="flex justify-between items-start pb-4 border-b border-[#2A2F45]/50">
              <div>
                <h1 className="text-2xl font-bold flex items-center gap-3">
                  {deployment.service}
                  <span className="text-sm font-mono text-[#8B91B5] bg-[#1C2030] px-2 py-0.5 rounded border border-[#2A2F45]">
                    {deployment.version}
                  </span>
                </h1>
                
                <div className="flex gap-4 mt-3 text-xs text-[#8B91B5]">
                  <span className="flex items-center gap-1.5 font-medium"><User size={13} /> {deployment.deployer}</span>
                  <span className="flex items-center gap-1.5 font-medium"><Clock size={13} /> {deployment.time}</span>
                  <span className={`px-2 py-0.5 rounded text-[10px] font-bold border ${envBadgeColor}`}>
                    {deployment.status}
                  </span>
                </div>
              </div>
              
              <RiskBadge score={deployment.risk} />
            </div>

            <div className="space-y-4">
              <h3 className="text-xs font-bold uppercase tracking-wider text-[#8B91B5]">Change Summary</h3>
              <p className="text-xs text-[#F0F2FF] bg-[#1C2030]/60 border border-[#2A2F45]/50 p-4 rounded-xl font-mono leading-relaxed">
                {deployment.changeSummary}
              </p>
              
              <div className="flex gap-4 pt-2">
                <button className="flex items-center gap-2 text-xs text-[#4F7FFF] hover:underline font-semibold bg-[#1C2030]/20 px-3 py-1.5 rounded-lg border border-[#2A2F45]">
                  <GitBranch size={13} /> Commit ({deployment.commit})
                </button>
                <button className="flex items-center gap-2 text-xs text-[#4F7FFF] hover:underline font-semibold bg-[#1C2030]/20 px-3 py-1.5 rounded-lg border border-[#2A2F45]">
                  <ExternalLink size={13} /> Jira Ticket {deployment.ticket}
                </button>
              </div>
            </div>
          </div>

          {/* Details on Infrastructure alteration */}
          {deployment.infraChanged && (
            <div className="bg-[#22D3EE]/5 border border-[#22D3EE]/25 rounded-xl p-5 space-y-2">
              <h4 className="text-xs font-bold text-[#22D3EE] uppercase tracking-widest flex items-center gap-1.5">
                <Terminal size={14} /> Infrastructure Modification Ingested
              </h4>
              <p className="text-xs text-[#8B91B5] leading-relaxed">
                {deployment.infraSummary || 'Modifications detected inside resource terraform scripts.'}
              </p>
            </div>
          )}

          {/* Risk Factors and Actions Card */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            
            {/* Risk factors */}
            <div className="card-bg rounded-xl p-5 border-l-4 border-l-[#EF4444] space-y-4">
              <h3 className="text-xs font-bold uppercase tracking-wider text-[#EF4444] flex items-center gap-1.5">
                <ShieldAlert size={14} /> Risk Analysis Indicators
              </h3>
              <ul className="space-y-3 text-xs text-[#8B91B5]">
                {riskFactors.map((f, idx) => (
                  <li key={idx} className="flex gap-2">
                    <span className="text-[#EF4444] font-bold">•</span>
                    <span>{f}</span>
                  </li>
                ))}
              </ul>
            </div>

            {/* Recommendations */}
            <div className="card-bg rounded-xl p-5 border-l-4 border-l-[#4F7FFF] space-y-4">
              <h3 className="text-xs font-bold uppercase tracking-wider text-[#4F7FFF] flex items-center gap-1.5">
                <CheckCircle2 size={14} /> Recommendations
              </h3>
              <ul className="space-y-3 text-xs text-[#8B91B5]">
                {recommendations.map((r, idx) => (
                  <li key={idx} className="flex gap-2">
                    <span className="text-[#4F7FFF] font-bold">•</span>
                    <span>{r}</span>
                  </li>
                ))}
              </ul>
            </div>

          </div>

        </div>

        {/* Right side: Circular Gauge & Hindsight memory panel */}
        <div className="lg:col-span-4 space-y-6">
          
          {/* Animated Gauge Card */}
          <div className="card-bg rounded-xl p-6 flex flex-col items-center text-center justify-center space-y-4">
            <h3 className="text-xs font-bold uppercase tracking-wider text-[#8B91B5]">AI Risk Index</h3>
            
            <div className="relative flex items-center justify-center">
              <svg className="w-32 h-32 transform -rotate-90">
                {/* Background Ring */}
                <circle 
                  className="stroke-[#1C2030]" 
                  fill="transparent" 
                  strokeWidth={stroke} 
                  r={normalizedRadius} 
                  cx={64} 
                  cy={64} 
                />
                {/* Progress Ring */}
                <circle 
                  className={`${gaugeColor} transition-all duration-1000 ease-out`} 
                  strokeDasharray={`${circumference} ${circumference}`} 
                  style={{ strokeDashoffset }} 
                  fill="transparent" 
                  strokeWidth={stroke} 
                  r={normalizedRadius} 
                  cx={64} 
                  cy={64} 
                />
              </svg>
              
              <div className="absolute flex flex-col items-center">
                <span className={`text-3xl font-extrabold ${gaugeText}`}>{deployment.risk}</span>
                <span className="text-[9px] text-[#8B91B5] font-bold uppercase">Score</span>
              </div>
            </div>

            <div>
              <p className="text-xs font-bold text-[#F0F2FF]">
                {deployment.risk > 80 ? 'CRITICAL SYSTEM RISK' :
                 deployment.risk > 60 ? 'ELEVATED REGRESSION PROBABILITY' :
                 deployment.risk > 30 ? 'MODERATE DEPLOYMENT RISK' :
                 'STABLE SIGNATURE APPROVED'
                }
              </p>
              <p className="text-[10px] text-[#8B91B5] mt-1">
                Compared to 15 similar deployments in the last 180 days.
              </p>
            </div>
          </div>

          {/* Hindsight Panel */}
          <HindsightPanel />

        </div>

      </div>

    </div>
  );
}